运行下面的代码，屏幕上将输出（ ）。
```cpp
#include <iostream>
using namespace std;

int divide(int a, int b) {
    if (b == 0) {
        throw runtime_error("division by zero error ");
    }
    return a / b;
}

int main() {
    int x = 10;
    int y = 0; // 设为 0 会导致除零错误

    try {
        int result = divide(x, y);
        cout << "result: " << result << endl;
    } catch (const runtime_error& e) {
        cout << "caught an exception: " << e.what() << endl;
    }

    return 0;
}
```

以下代码用递推法求斐波那契数列的第 n 项，时间复杂度为指数级。
```cpp
int fibonacci(int n) {
    if (n == 0) return 0;
    if (n == 1) return 1;
    int f0 = 0, f1 = 1, current;
    for (int i = 2; i <= n; i++) {
        current = f0 + f1;
        f0 = f1;
        f1 = current;
    }
    return current;
}
```

